using CollegeManagementSystem.Data.Entities;using Microsoft.EntityFrameworkCore;namespace CollegeManagementSystem.Data;public class AppDbContext : DbContext{    public AppDbContext(DbContextOptions<AppDbContext> options) : base(options)    {    }    public DbSet<Course> Courses { get; set; }    public DbSet<Module> Modules { get; set; }    public DbSet<Student> Students { get; set; }    public DbSet<ModuleInstructor> ModuleInstructors { get; set; }    public DbSet<Instructor> Instructors { get; set; }    public DbSet<Enrollment> Enrollments { get; set; }}